import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from "./componentes/TopoOferta";
import Rodape from "./componentes/Rodape";

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [etapa, setEtapa] = useState('vitrine'); 
  const [modoCadastro, setModoCadastro] = useState(false);
  const [usuario, setUsuario] = useState(() => {
    const salvo = localStorage.getItem('usuario_logado');
    return salvo ? JSON.parse(salvo) : null;
  });
  const [formaPagamento, setFormaPagamento] = useState('');
  const [pedidoFinalizado, setPedidoFinalizado] = useState(null);
  const [historico, setHistorico] = useState([]);
  const [origemLogin, setOrigemLogin] = useState('checkout');
  const [formData, setFormData] = useState({ nome: '', email: '', senha: '', telefone: '', cep: '', endereco: '', cpf: '' });

  // 1. FUNÇÃO DE LOGOUT (Para destravar Paloma)
  const fazerLogout = () => {
    localStorage.removeItem('usuario_logado');
    setUsuario(null);
    setEtapa('vitrine');
    window.location.reload(); 
  };

  // 2. USEEFFECT UNIFICADO (Busca produtos e aplica descontos da VIEW)
  useEffect(() => {
    const carregarDadosIniciais = async () => {
      try {
        const [resProd, resOfertas] = await Promise.all([
          fetch("http://localhost:3001/produtos"),
          fetch("http://localhost:3001/api/promocao_10")
        ]);

        const produtosNormais = await resProd.json();
        const ofertasView = await resOfertas.json();

        const produtosAtualizados = produtosNormais.map(p => {
          const oferta = ofertasView.find(o => o.id === p.id);
          if (oferta) {
            return { 
              ...p, 
              Desconto_10porct: oferta.Desconto_10porct, 
              Valor_antigo: p.valor 
            };
          }
          return p;
        });

        setProdutos(produtosAtualizados);
      } catch (err) {
        console.error("Erro ao carregar dados:", err);
      }
    };
    carregarDadosIniciais();
  }, []);

  // 3. CÁLCULO DO TOTAL COM DESCONTO
  const totalProd = carrinho.reduce((acc, i) => {
    const precoEfetivo = i.Desconto_10porct ? parseFloat(i.Desconto_10porct) : parseFloat(i.valor);
    return acc + (precoEfetivo * (i.qtd || 1));
  }, 0);

  const valorFrete = formaPagamento === 'pix' ? 0 : 15.00;

  // FUNÇÕES AUXILIARES
  const adicionarAoCarrinho = (p) => {
    const itemExiste = carrinho.find(item => item.id === p.id);
    if (itemExiste) {
      setCarrinho(carrinho.map(item => item.id === p.id ? { ...item, qtd: item.qtd + 1 } : item));
    } else {
      setCarrinho([...carrinho, { ...p, qtd: 1 }]);
    }
  };

  const carregarHistorico = async () => {
    const userAtivo = usuario || JSON.parse(localStorage.getItem('usuario_logado'));
    if (!userAtivo) {
      setOrigemLogin('historico');
      setEtapa('login');
      return;
    }
    const idParaBusca = userAtivo.id_cliente || userAtivo.id;
    try {
      const response = await fetch(`http://localhost:3001/historico/${idParaBusca}`);
      const dados = await response.json();
      setHistorico(Array.isArray(dados) ? dados : []);
      setEtapa('historico');
    } catch (err) {
      alert("Erro ao buscar histórico.");
    }
  };

  const handleAuth = async () => {
    const rota = modoCadastro ? 'cadastrar' : 'login';
    try {
      const response = await fetch(`http://localhost:3001/${rota}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData)
      });
      const dados = await response.json();
      if (response.ok) {
        setUsuario(dados);
        localStorage.setItem('usuario_logado', JSON.stringify(dados));
        if (origemLogin === 'historico') carregarHistorico(dados);
        else setEtapa('checkout');
      } else {
        alert(dados.message || "Erro");
      }
    } catch (err) {
      alert("Erro de conexão");
    }
  };

  return (
    <div className="App">
      <Topo 
        totalItens={carrinho.length} 
        abrirCarrinho={() => setEtapa('carrinho')} 
        verHistorico={carregarHistorico} 
        usuarioLogado={usuario} 
        onLogout={fazerLogout} // Aqui passa a função para o Topo
      />

      <main className="conteudo-principal">
        {etapa === 'vitrine' && (
          <div className="grid-produtos">
            {produtos.map(p => (
              <div key={p.id} className="card">
                {p.Desconto_10porct && <div className="badge-promo">10% OFF</div>}
                <img src={p.imagem_url || p.foto} alt={p.produto} />
                <h3>{p.produto}</h3>
                <div className="preco-container">
                  {p.Desconto_10porct ? (
                    <>
                      <span className="preco-antigo" style={{textDecoration: 'line-through'}}>R$ {parseFloat(p.valor).toFixed(2)}</span>
                      <span className="preco-novo">R$ {parseFloat(p.Desconto_10porct).toFixed(2)}</span>
                    </>
                  ) : (
                    <span>R$ {parseFloat(p.valor).toFixed(2)}</span>
                  )}
                </div>
                <button className="btn-comprar" onClick={() => adicionarAoCarrinho(p)}>Comprar</button>
              </div>
            ))}
          </div>
        )}

        {/* ... Outras etapas (carrinho, login, etc) permanecem iguais ao seu código anterior */}
        {etapa === 'historico' && (
           <div className="container-venda">
              <h2>📋 Histórico</h2>
              {historico.map((h, i) => <p key={i}>Pedido #{h.numero_pedido} - {h.itens_do_pedido}</p>)}
              <button onClick={() => setEtapa('vitrine')}>Voltar</button>
           </div>
        )}
      </main>
      <Rodape />
    </div>
  );
}

export default App;
